// Helper function to generate CV download button
function getCVButton(content) {
  const cv = content.cv || content.resume;
  const showCV = content.showCV !== false;
  const buttonText = content.cvButtonText || 'Download CV';
  
  if (!cv || !showCV) return '';
  
  return `
    <a href="${cv}" download="${content.cvFileName || 'resume.pdf'}" class="btn btn-cv">
      <i class="fas fa-download"></i>
      ${buttonText}
    </a>
  `;
}

